import {getAuth, signInWithPopup, GoogleAuthProvider} from 'firebase/auth';
import { initializeApp, } from 'firebase/app';
import { getFirestore, collection, getDoc, setDoc, addDoc, onSnapshot, doc, writeBatch, WriteBatch  } from 'firebase/firestore';
import { Title } from '../components/menu-container/menu-container.styles';



//initialize firebase app
const config = {
    apiKey: "AIzaSyAPACQwkLYDOQuXLUVTYlf713lJizzn1nc",
  authDomain: "crown-db-179d8.firebaseapp.com",
  projectId: "crown-db-179d8",
  storageBucket: "crown-db-179d8.appspot.com",
  messagingSenderId: "1098129687717",
  appId: "1:1098129687717:web:cde51e5e1134cabb39394c",
  measurementId: "G-58Q6J6X6Q5"
};
const app = initializeApp(config);

//initialize database
export const db = getFirestore();

//export sign in with email and password


//create an instance, and authenticating using Google provider object
const provider = new GoogleAuthProvider();
provider.setCustomParameters({ prompt: 'select_account' });
export const auth = getAuth();
export const signInPopUp = () => (signInWithPopup(auth, provider));
//  .then((result)=>{
//    const user = result.user;
//    console.log(user)
//  })
//  .catch((error) => {
//    const errorCode = error.code;
//    const errorMessage = error.message;
//    console.log(errorCode, errorMessage);
//  });


//Query to read doc from database


//trim down collections snapshot to relevant objects 
export const convertCollectionsSnapshotToMap = (collections) => {
  const transformedSnapshot = collections.docs.map(doc => {
    const {title, item } = doc.data();
    return (
      {
        routeName: encodeURI(title.toLowerCase()),
        id: doc.id,
        title, 
        items
      }
    )
  });

  return transformedSnapshot.reduce((accumulator, collection) => {
    accumulator[collection.title.toLowerCase()] = collection;
    return accumulator;
    }, {});
};

//store collections into firebase
export const addCollectionAndDocument = async (collectionKey, objectsToAdd) => {
  const collectionRef = collection(db, collectionKey); 
  console.log(collectionRef);

  objectsToAdd.forEach(obj => {
    const docRef = obj.getDocs()
    console.log("get docs", docRef)
  })
};

//store user into database
export const createUserProfileDocument = async (authUser, additionalData) => {
  if (!authUser) return;
  
  const docRef = doc(db, 'users', authUser.uid);

  const docSnap = await getDoc(docRef);
 
  if (!docSnap.exists()) {
    const { displayName, email } =  authUser;
    const createdAt = new Date();

    try {
      await setDoc(docRef, {
        displayName,
        email,
        createdAt, 
        ...additionalData
        }
      )

    } catch (error) {
      console.log('An error occured', error.message)
    }    
  }

  return docRef;
  
}
